var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이 영상...... 어떻게 된 거야?","JPN":"この映像……いったい何だ？","ENG":"This video... What is it?","TWN":"咦？這影片……是怎麼回事?"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L4_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아카데미라면...... 관리국이 세운 카운터 전용 교육시설 얘긴가?","JPN":"アカデミー……？　管理局が建てたカウンター専用の教育施設のこと？","ENG":"The Academy? Is that the new Counter training institute that the Administration has established?","TWN":"如果妳是指裡面的學校……聽說是管理局建立的制裁者專用教育設施?"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아무래도 기대하던 고급 기술자료는 안 들어 있는 것 같네요.","JPN":"どうやら期待していたような高級技術資料は入っていないようですね。","ENG":"I don't think this contains high-tech data like we hoped for.","TWN":"但不管怎麼說，裡面似乎沒有我們期待已久的高級技術資料。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"아니, 그런 것보다 이거, 로스트 쉽이잖아?","JPN":"いや、そんなことよりここってロストシップだろ？","ENG":"That's not important. This is a Lost Ship.","TWN":"比起這個，你們看，這是失落艦船吧？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"어째서 함선에 이런 일상 기록이 남아 있는 거야? 우리보다 누가 먼저 여기 왔던 걸까?","JPN":"どうして艦船にこんな日常的な記録が残ってるんだ？\\n私たちより先に来た人がいるってこと？","ENG":"Why does it carry such mundane records? Was someone here before us?","TWN":"這艦船內為什麼還留存著這種日常記錄？ 還有誰比我們先來過這裡嗎？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그건 아닌 것 같아요. 여기 영상기록을 촬영한 시간을 보세요.","JPN":"それは違うと思いますよ。ほらここ、映像が撮影された時間を見てください。","ENG":"I doubt it. Check out the timestamp of the video.","TWN":"似乎不是這樣，妳們看這裡的影像記錄時間。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"응?","JPN":"えっ？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"기록 후 경과시간이...... 497만 시간?","JPN":"記録後の経過時間が……497万時間？","ENG":"It's been... 4,970,000 hours since it was recorded?","TWN":"記錄後經過了………497萬小時？！！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"햇수로 따지면 거의 600년이죠.","JPN":"年数で数えたら、ほぼ600年ですね。","ENG":"That's almost 600 years.","TWN":"按年份算一算，差不多有600年了吧。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"뭐어?!","JPN":"ええっ！？","ENG":"What?","TWN":"什麼？！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"기, 기계가 침식파 때문에 고장난 거겠지. 600년 된 캠코더가 있을 리 없잖아.","JPN":"き、機械が侵食波のせいで壊れたに決まってる。\\n600年前のカメラがあるわけないだろ。","ENG":"Th-this machine has to be broken because of the Corruption rays. There's no way this camcorder is 600 years old.","TWN":"這...這機器怕不是受侵蝕波影響而出了故障吧？ 怎麼可能有存在了600年的攝影機啊。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L14_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"글쎄요. 장담은 못하겠지만, 여긴 이면세계니까 영상 속 장소와 타임 싱크로가 어긋났을 가능성도......","JPN":"どうでしょう。断言はできませんが、ここは裏世界だから\\n映像に写っている場所と時間がずれている可能性も……","ENG":"Who knows? I'm not sure, but it's possible that time and space are distorted in the Counterside...","TWN":"是啊，雖然不敢確定，但因為這裡是異界，所以影片中時空的同步有可能發生錯亂吧..."},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이 소린......","JPN":"この音は……","ENG":"This noise...","TWN":"這聲音.....?"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"아까 오는 길에 설치해 뒀던 감지기 소리에요.","JPN":"来る途中に設置しておいた感知器の音ですね。","ENG":"It's from the sensor I set up on our way here.","TWN":"是我在來的路上設置的感應器發出的聲音。"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"제나~ 캐시~ 얼른 나와 봐~","JPN":"ジーナ～キャシ～早く出てきて～！","ENG":"Zena! Cathy! Come out here!","TWN":"珍娜~~凱西~~趕快出來吧~"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"가까운 곳에 다이브 진입 좌표가 열렸어. 이쪽으로 오려나 봐.","JPN":"この近くにダイブ進入座標が開いたわ。こっちに来るみたい。","ENG":"A Dive portal has opened nearby. Someone's coming.","TWN":"我已經就近打開了躍入的座標，快來這裡！"},"stage":{"bg":"CORRIDOR","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이런...... 벌써 발굴팀이 온 건가?","JPN":"しまった……もう発掘チームが来たのか？","ENG":"Oh, no. The excavation team is already here?","TWN":"這是……莫非勘探隊已經來了?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그건 아닌 것 같아요.","JPN":"それは違うと思います。","ENG":"I don't think so.","TWN":"似乎不是。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"응? 그럼?","JPN":"うん？　じゃあ何？","ENG":"Mm? Then, who else?","TWN":"嗯？那.....?"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"소대장이 말한 대로 여긴 침식체가 없는 유클리드 섹터에요.","JPN":"ジーナが言ったとおり、ここは侵食体がいないユークリッドセクターです。","ENG":"Commander, as you said, this is the Euclid Sector where there's no C.O.","TWN":"正如小隊長所說，這裡是無侵蝕體的歐幾里得防區。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"발굴대 정도면 호위는 용병들로 충분해요. 저렇게 기갑 부대를 동원할 리 없어요.","JPN":"発掘隊の護衛なら傭兵で十分、あのような機甲部隊を動員するはずがありません。","ENG":"If it was the excavation team, it would only have come with a few mercenaries for its protection, not with an armored force like that.","TWN":"真要到了出動勘探隊的話，派出守衛這裡的雇傭兵就夠了，不可能出動這種規模的裝甲部隊。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"그리고 이거, 감지기로 찍은 영상인데요.","JPN":"あとこれ、感知器で撮った映像ですが。","ENG":"And look, this was captured on our sensor.","TWN":"還有，這是感應器拍到的影像。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L38_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"이게 뭐야......? 침식체는 아닌데......?","JPN":"これ何だ……？　侵食体ではなさそうだけど……？","ENG":"What are they? They don't look like C.O.","TWN":"這是，什麼啊…？這不是侵蝕體嗎…？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"IRIE_CIVIL_NULL_NULL","text":{"KOREA":"사람 같게도 안 생겼어~","JPN":"人にも見えないわ～。","ENG":"They don't look like humans, either.","TWN":"長得不像人呢~"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"IRIE_CIVIL_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"꼭 사람이랑 침식체를 반씩 섞어 놓은 것 같죠?","JPN":"まるで人間と侵食体を半分ずつ混ぜたような感じでしょう？","ENG":"They look like hybrids between man and C.O., don't they?","TWN":"像是人和侵蝕體各一半混在一起的感覺，是吧？"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ZENA_CIVIL_NULL_NULL","text":{"KOREA":"그래. 이런 병사들이 있다는 얘긴 들어본 적 없어.","JPN":"そうだな。こんな兵士がいるって話は聞いたことがない。","ENG":"Yes. But I've never heard of soldiers like that before.","TWN":"嗯，我從來沒聽說過有這樣的士兵。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ZENA_CIVIL_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"......저도 마찬가지에요.","JPN":"……私もです。","ENG":"Neither have I.","TWN":"……我也是。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"느낌이 안 좋아요. 상황이 더 심각해지기 전에 여길 뜨죠.","JPN":"嫌な予感がします。状況が悪化する前にここを離れましょう。","ENG":"I have a bad feeling about them. We'd better get out of here before things get worse.","TWN":"感覺不太妙。在情況變得更糟糕之前，我們快離開這兒吧。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"CATHY_CIVIL_NULL_NULL","text":{"KOREA":"확인해야 할 건 잔뜩 남았지만...... 이 이상 엮이면 너무 위험해지겠어요.","JPN":"確認すべきこともたくさん残ってますが……これ以上関わると危険です。","ENG":"There are many things I want to check, but I don't want to get involved with them. That's just too dangerous.","TWN":"雖然還有很多東西需要確認...但如果再這樣下去太危險了。"},"stage":{"bg":"COUNTERSIDE_NORMAL","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CATHY_CIVIL_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};